import collections

def find_maximal_cliques(graph_dict):
    maximal_cliques = []

    all_vertices = set(graph_dict.keys())
    for u in graph_dict:
        all_vertices.update(graph_dict[u])

    adj = collections.defaultdict(set)
    for v in all_vertices:
        adj[v].update(graph_dict.get(v, set()))

    for u in list(adj.keys()):
        for v in adj[u]:
            adj[v].add(u)

    def bron_kerbosch_recursive(R_current, P_candidates, X_excluded):
        if not P_candidates and not X_excluded:
            if R_current:
                maximal_cliques.append(R_current)
            return

        pivot = None
        max_intersection_size = -1

        for v in P_candidates:
            intersection_size = len(adj[v].intersection(P_candidates))
            if intersection_size > max_intersection_size:
                max_intersection_size = intersection_size
                pivot = v

        for v in X_excluded:
            intersection_size = len(adj[v].intersection(P_candidates))
            if intersection_size > max_intersection_size:
                max_intersection_size = intersection_size
                pivot = v

        if pivot is None:
            iter_set = set()
        else:
            iter_set = P_candidates.difference(adj[pivot])

        for v in list(iter_set):
            bron_kerbosch_recursive(
                R_current.union({v}),
                P_candidates.intersection(adj[v]),
                X_excluded.intersection(adj[v])
            )

            P_candidates.remove(v)
            X_excluded.add(v)

    bron_kerbosch_recursive(frozenset(), set(all_vertices), set())

    return [set(c) for c in maximal_cliques]
